#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int lis[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &lis[i]);
        }
        long long dp[n + 1][n + 1] = {0};
        dp[0][0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= i; j++) {
                for (int k = 1; k <= 9; k++) {
                    if (j == lis[i - 1]) {
                        dp[i][j] += dp[i - 1][j - 1];
                    } else if (j < lis[i - 1]) {
                        dp[i][j] += dp[i - 1][j];
                    }
                }
                dp[i][j] %= MOD;
            }
        }
        long long ans = 0;
        for (int i = 1; i <= n; i++) {
            ans += dp[n][i];
        }
        printf("%lld\n", ans % MOD);
    }
    return 0;
}

